#!/usr/bin/env node
// Builds docs/explorer/explorer-data.js from the repo's single sources of truth:
//   - schemas/*.schema.json   (construct, indicators, lenses, required fields)
//   - ontology/edges.json     (the 28 typed edges)
//   - docs/research/research.json (frontier anchors + per-construct grounding)
//
// Zero npm dependencies — Node fs only. Re-running with no source changes
// produces no diff (deterministic, no timestamps). The explorer opens via
// file:// and loads the generated file with <script src> — no server needed.
//
// Usage:  node scripts/build-explorer.mjs   (add --check to fail on drift)

import { readFileSync, writeFileSync, readdirSync, mkdirSync, existsSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const read = (p) => readFileSync(join(root, p), "utf8");
const readJSON = (p) => JSON.parse(read(p));

const checkOnly = process.argv.includes("--check");

// --- load sources -----------------------------------------------------------
const edgesDoc = readJSON("ontology/edges.json");
const research = readJSON("docs/research/research.json");

const schemaDir = "schemas";
const schemaFiles = readdirSync(join(root, schemaDir))
  .filter((f) => f.endsWith(".schema.json"))
  .sort();

const frontierById = Object.fromEntries(research.frontier.map((f) => [f.id, f]));

// --- derive per-construct records -------------------------------------------
const constructs = schemaFiles.map((file) => {
  const s = readJSON(join(schemaDir, file));
  const props = s.properties || {};
  const id = props.construct?.const;
  if (!id) throw new Error(`No construct const in ${file}`);

  const ind = props.indicators || {};
  const indicators = (ind.items && ind.items.enum) || ind.enum || [];

  const lensProp = props.interpretation?.properties?.lens || {};
  const lenses = (lensProp.enum || []).filter((l) => l !== "none");

  const edgesOut = edgesDoc.edges
    .filter((e) => e.from === id)
    .map((e) => ({ to: e.to, type: e.type }));
  const edgesIn = edgesDoc.edges
    .filter((e) => e.to === id)
    .map((e) => ({ from: e.from, type: e.type }));

  const r = research.constructs[id] || {};
  const papers = (r.papers || []).map((pid) => {
    const f = frontierById[pid];
    if (!f) throw new Error(`research.json: construct '${id}' references unknown paper id '${pid}'`);
    return { title: f.title, url: f.url, authors: f.authors, year: f.year, venue: f.venue, note: f.note };
  });

  return {
    id,
    title: s.title || id,
    description: s.description || "",
    indicators,
    lenses,
    required: s.required || [],
    degree: edgesOut.length + edgesIn.length,
    edgesOut,
    edgesIn,
    research: { frame: r.frame || "", labs: r.labs || [], papers },
  };
});

// --- integrity checks -------------------------------------------------------
const ids = new Set(constructs.map((c) => c.id));
for (const e of edgesDoc.edges) {
  if (!ids.has(e.from) || !ids.has(e.to)) {
    throw new Error(`edges.json references unknown construct: ${e.from} -> ${e.to}`);
  }
}
if (constructs.length !== 12) throw new Error(`Expected 12 constructs, found ${constructs.length}`);
if (edgesDoc.edges.length !== 28) throw new Error(`Expected 28 edges, found ${edgesDoc.edges.length}`);

// --- emit -------------------------------------------------------------------
const payload = {
  schemaVersion: research.schemaVersion,
  thesis: research.thesis,
  nonClinicalBoundary: research.nonClinicalBoundary,
  edgeTypes: edgesDoc.edgeTypes,
  constructs,
  edges: edgesDoc.edges,
  frontier: research.frontier,
};

const banner =
  "// GENERATED by scripts/build-explorer.mjs — do not edit by hand.\n" +
  "// Sources: schemas/*.schema.json, ontology/edges.json, docs/research/research.json\n";
const out = banner + "window.HMIS_DATA = " + JSON.stringify(payload, null, 2) + ";\n";

const outPath = "docs/explorer/explorer-data.js";
const outAbs = join(root, outPath);

if (checkOnly) {
  const existing = existsSync(outAbs) ? readFileSync(outAbs, "utf8") : "";
  if (existing !== out) {
    console.error(`DRIFT: ${outPath} is stale. Run: node scripts/build-explorer.mjs`);
    process.exit(1);
  }
  console.log(`OK: ${outPath} is in sync (12 constructs, 28 edges).`);
} else {
  mkdirSync(dirname(outAbs), { recursive: true });
  writeFileSync(outAbs, out);
  console.log(`Wrote ${outPath}: ${constructs.length} constructs, ${edgesDoc.edges.length} edges, ${research.frontier.length} frontier anchors.`);
}
